document.addEventListener("DOMContentLoaded",function(){var c=document.querySelectorAll(".hj-treatments-block");c.forEach(function(l){var o=l.querySelectorAll(".hj-tb-section__toggle");o.forEach(function(e){e.addEventListener("click",function(){var t=e.closest(".hj-tb-section"),a=e.getAttribute("aria-controls"),s=a?document.getElementById(a):null;if(!(!t||!s)){var n=t.classList.contains("is-collapsed");t.classList.toggle("is-collapsed",!n),e.setAttribute("aria-expanded",n?"true":"false"),s.hidden=!n}})})})});
